const call = $json.call;
const custom = call.call_analysis?.custom_analysis_data ?? {};

// Build full name from split fields; fall back to legacy patientName
const firstName = custom.patientFirstName ?? '';
const lastName = custom.patientLastName ?? '';
const patientName = [firstName, lastName].filter(Boolean).join(' ') || custom.patientName || 'Patient';
const greeting = firstName || patientName;

// Use Ava-confirmed phone number from custom data; fall back to caller ID
const patientPhone = custom.patientPhone ?? call.from_number ?? null;
const patientEmail = custom.patientEmail ?? null;
const appointmentDate = custom.appointmentDate ?? null;
const appointmentTime = custom.appointmentTime ?? null;
const clinicianName = custom.clinicianName ?? 'our physiotherapist';
const appointmentType = custom.appointmentType === 'follow_up' ? 'follow-up appointment' : 'initial assessment';

// SMS body — uses first name for warmth
const smsBody = `Hi ${greeting}, your ${appointmentType} at Spires Physiotherapy with ${clinicianName} is confirmed${appointmentDate ? ` for ${appointmentDate}` : ''}${appointmentTime ? ` at ${appointmentTime}` : ''}. Reply CANCEL to cancel (24h notice required). See you soon.`;

// Email body (plain text)
const emailBody = `Hi ${greeting},\n\nYour ${appointmentType} at Spires Physiotherapy is confirmed.\n\n${appointmentDate ? `Date: ${appointmentDate}` : ''}\n${appointmentTime ? `Time: ${appointmentTime}` : ''}\nClinician: ${clinicianName}\n\nWhat to bring:\n- Comfortable clothing that allows access to the area being treated\n- Any relevant scans, X-rays, or letters from your GP (or email them to info@spiresphysiotherapy.com beforehand)\n\nAddress: Compayne Gardens, West Hampstead, London NW6 3DD\nNearest station: West Hampstead (Jubilee / Thameslink / Overground — 5 min walk)\nParking: On-street on Compayne Gardens — no permit needed evenings or weekends\n\nIf you need to cancel or rebook, please give us 24 hours' notice. Call 020 7118 1278 and Ava will help.\n\nSee you soon,\nThe Spires Physiotherapy team`;

return [{
  patientFirstName: firstName || null,
  patientLastName: lastName || null,
  patientName,
  greeting,
  patientPhone,
  patientEmail,
  smsBody,
  emailBody,
  emailSubject: `Appointment confirmed — Spires Physiotherapy${appointmentDate ? `, ${appointmentDate}` : ''}`,
  callId: call.call_id,
  hasPhone: !!patientPhone,
  hasEmail: !!patientEmail,
}];
